n = int(input())

def is_square(n):
    if n < 0:
        return False
    if n == 0 or n == 1:
        return True
    start = 0
    end = n
    while start <= end:
        mid = (start + end) // 2
        if mid * mid == n:
            return True
        if mid * mid < n:
            start = mid + 1
        else:
            end = mid - 1
    return False

if is_square(n):
    print(n)
else:
    for i in range(n, 0, -1):
        if is_square(i):
            print(i)
            break
